Here is the complete, interactive Team Kanban Board designed strictly in accordance with Robert Murdock's **Polaris / Material Design 3 system**. 

It is a single, self-contained, real-time synchronized file that starts directly with the functional interface (excluding redundant branding headers), utilizes custom initials circles for the mandatory team assignees, and populates realistic tasks referencing files in your workspace.

```html
<!-- index.html -->
<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Team Kanban Board</title>
  <!-- Google Fonts -->
  <link href="https://fonts.googleapis.com/css2?family=Google+Sans:wght@400;500;700&family=Google+Sans+Text:wght@400;500&display=swap" rel="stylesheet">
  <!-- Tailwind CSS -->
  <script src="https://cdn.tailwindcss.com"></script>
  <style>
    :root {
      --gemini-rail-icon-gap: 0px;
      --gemini-side-panel-padding-left: 16px;
      --gemini-side-panel-padding-right: 16px;
      --gemini-header-padding-left: 10px;
      --gemini-header-padding-right: 12px;
      --gemini-header-elements-gap: 8px;
    }
    body {
      font-family: 'Google Sans Text', sans-serif;
      background-color: #ffffff;
      color: #1f1f1f;
    }
    h1, h2, h3, button, select, input {
      font-family: 'Google Sans', sans-serif;
    }
    .column-bg {
      background-color: #f0f4f9;
    }
    .primary-btn {
      background-color: #0b57d0;
      color: #ffffff;
    }
    .primary-btn:hover {
      background-color: #0842a0;
    }
    .dragging {
      opacity: 0.4;
      border-style: dashed !important;
      border-color: #0b57d0 !important;
    }
  </style>
</head>
<body class="bg-white">

  <div class="max-w-6xl mx-auto p-4 md:p-6 space-y-6">
    <!-- Controls Panel: Filter & Quick Add -->
    <div class="flex flex-col md:flex-row md:items-center md:justify-between gap-4 border-b border-slate-100 pb-4">
      <!-- Search & Filter -->
      <div class="flex flex-wrap items-center gap-2">
        <input type="text" id="searchInput" placeholder="Search tasks..." oninput="filterTasks()" class="px-3 py-1.5 text-xs rounded-md border border-slate-200 focus:outline-none focus:border-[#0b57d0] w-48 bg-white">
        <select id="filterAssignee" onchange="filterTasks()" class="px-2 py-1.5 text-xs rounded-md border border-slate-200 focus:outline-none focus:border-[#0b57d0] bg-white">
          <option value="">All Assignees</option>
          <option value="Sakura Okoro">Sakura Okoro</option>
          <option value="Malik Harold">Malik Harold</option>
          <option value="Adam Lee">Adam Lee</option>
        </select>
      </div>

      <!-- Quick Add Form -->
      <form id="quickAddForm" onsubmit="addTask(event)" class="flex flex-wrap items-center gap-2">
        <input type="text" id="newTaskTitle" placeholder="Add a new task..." required class="px-3 py-1.5 text-xs rounded-md border border-slate-200 focus:outline-none focus:border-[#0b57d0] w-48 md:w-64 bg-white">
        <select id="newTaskAssignee" class="px-2 py-1.5 text-xs rounded-md border border-slate-200 focus:outline-none focus:border-[#0b57d0] bg-white">
          <option value="Sakura Okoro">Sakura Okoro</option>
          <option value="Malik Harold">Malik Harold</option>
          <option value="Adam Lee">Adam Lee</option>
        </select>
        <select id="newTaskStatus" class="px-2 py-1.5 text-xs rounded-md border border-slate-200 focus:outline-none focus:border-[#0b57d0] bg-white">
          <option value="todo">To Do</option>
          <option value="in-progress">In Progress</option>
          <option value="done">Done</option>
        </select>
        <button type="submit" class="primary-btn text-xs font-medium px-4 py-1.5 rounded-md transition-colors">Add</button>
      </form>
    </div>

    <!-- Board Grid -->
    <div class="grid grid-cols-1 md:grid-cols-3 gap-6">

      <!-- TO DO -->
      <div class="flex flex-col rounded-lg p-4 column-bg min-h-[500px]" ondragover="allowDrop(event)" ondrop="drop(event, 'todo')">
        <div class="flex items-center justify-between mb-3 px-1">
          <h3 class="text-sm font-medium text-slate-700 flex items-center gap-2">To Do <span id="count-todo" class="text-xs bg-slate-200 text-slate-600 px-2 py-0.5 rounded-full">0</span></h3>
        </div>
        <div id="col-todo" class="space-y-3 flex-1 overflow-y-auto"></div>
      </div>

      <!-- IN PROGRESS -->
      <div class="flex flex-col rounded-lg p-4 column-bg min-h-[500px]" ondragover="allowDrop(event)" ondrop="drop(event, 'in-progress')">
        <div class="flex items-center justify-between mb-3 px-1">
          <h3 class="text-sm font-medium text-slate-700 flex items-center gap-2">In Progress <span id="count-in-progress" class="text-xs bg-slate-200 text-slate-600 px-2 py-0.5 rounded-full">0</span></h3>
        </div>
        <div id="col-in-progress" class="space-y-3 flex-1 overflow-y-auto"></div>
      </div>

      <!-- DONE -->
      <div class="flex flex-col rounded-lg p-4 column-bg min-h-[500px]" ondragover="allowDrop(event)" ondrop="drop(event, 'done')">
        <div class="flex items-center justify-between mb-3 px-1">
          <h3 class="text-sm font-medium text-slate-700 flex items-center gap-2">Done <span id="count-done" class="text-xs bg-slate-200 text-slate-600 px-2 py-0.5 rounded-full">0</span></h3>
        </div>
        <div id="col-done" class="space-y-3 flex-1 overflow-y-auto"></div>
      </div>

    </div>
  </div>

  <script>
    const envId = window.__sandboxEnvId;
    const syncKey = "team_kanban_board_state";

    // Standard workspace team members
    const teamMembers = [
      { name: "Sakura Okoro", email: "sakura@example.com", initials: "SO", color: "#0f766e" },
      { name: "Malik Harold", email: "malik@example.com", initials: "MH", color: "#1d4ed8" },
      { name: "Adam Lee", email: "adam@example.com", initials: "AL", color: "#b45309" }
    ];

    // Preloaded tasks containing context from the hospital files
    let tasks = [
      { id: "task-1", title: "Automate EHR severity tags (ESI level)", status: "todo", assignee: "Sakura Okoro", doc: "patient_inquiry_and_triage_flow.doc" },
      { id: "task-2", title: "Monitor triage-to-bed allocation latency", status: "in-progress", assignee: "Malik Harold", doc: "patient_inquiry_and_triage_flow.doc" },
      { id: "task-3", title: "Mandate SBAR handoff protocols prior to transfer", status: "done", assignee: "Adam Lee", doc: "patient_inquiry_and_triage_flow.doc" },
      { id: "task-4", title: "Build Live Care Journey Tracker framework", status: "todo", assignee: "Sakura Okoro", doc: "patient_experience_h2_roadmap_spec.gdoc" },
      { id: "task-5", title: "Incorporate interactive PACU to Ward map transitions", status: "in-progress", assignee: "Malik Harold", doc: "patient_experience_h2_roadmap_spec.gdoc" },
      { id: "task-6", title: "Configure patient satisfaction metric SMS triggers", status: "done", assignee: "Adam Lee", doc: "hospital_journey_executive_deck.gslides" }
    ];

    let isSaving = false;
    let draggedId = null;

    // Real-Time Synchronization API Helper
    async function loadSyncedState() {
      if (!envId) return;
      try {
        const res = await fetch(`/api/sync/${envId}/${syncKey}`);
        const json = await res.json();
        if (json.data && !isSaving) {
          // Avoid active input focus resetting by rendering only when states actually differ
          if (JSON.stringify(tasks) !== JSON.stringify(json.data)) {
            tasks = json.data;
            renderBoard();
          }
        }
      } catch (err) {
        console.error("Failed to load synced state:", err);
      }
    }

    async function saveSyncedState(newState) {
      if (!envId) return;
      isSaving = true;
      try {
        await fetch(`/api/sync/${envId}/${syncKey}`, {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({ data: newState })
        });
      } catch (err) {
        console.error("Failed to save synced state:", err);
      } finally {
        isSaving = false;
      }
    }

    // HTML5 Drag and Drop Handlers
    function dragStart(e) {
      draggedId = e.target.id;
      e.target.classList.add('dragging');
      e.dataTransfer.setData('text/plain', e.target.id);
    }

    function dragEnd(e) {
      e.target.classList.remove('dragging');
    }

    function allowDrop(e) {
      e.preventDefault();
    }

    function drop(e, columnStatus) {
      e.preventDefault();
      const id = e.dataTransfer.getData('text/plain') || draggedId;
      if (id) {
        updateTaskStatus(id, columnStatus);
      }
    }

    // Task Actions
    function updateTaskStatus(id, newStatus) {
      tasks = tasks.map(t => t.id === id ? { ...t, status: newStatus } : t);
      renderBoard();
      saveSyncedState(tasks);
    }

    function updateTaskAssignee(id, newAssignee) {
      tasks = tasks.map(t => t.id === id ? { ...t, assignee: newAssignee } : t);
      renderBoard();
      saveSyncedState(tasks);
    }

    function deleteTask(id) {
      tasks = tasks.filter(t => t.id !== id);
      renderBoard();
      saveSyncedState(tasks);
    }

    function addTask(e) {
      e.preventDefault();
      const titleInput = document.getElementById('newTaskTitle');
      const assigneeSelect = document.getElementById('newTaskAssignee');
      const statusSelect = document.getElementById('newTaskStatus');

      if (!titleInput || !titleInput.value.trim()) return;

      const newTask = {
        id: 'task-' + Date.now(),
        title: titleInput.value.trim(),
        status: statusSelect.value,
        assignee: assigneeSelect.value,
        doc: '' 
      };

      tasks.push(newTask);
      titleInput.value = '';

      renderBoard();
      saveSyncedState(tasks);
    }

    function filterTasks() {
      renderBoard();
    }

    function escapeHtml(string) {
      return String(string).replace(/[&<>"']/g, function (s) {
        return {
          '&': '&amp;',
          '<': '&lt;',
          '>': '&gt;',
          '"': '&quot;',
          "'": '&#39;'
        }[s];
      });
    }

    function renderCard(task) {
      const member = teamMembers.find(m => m.name === task.assignee) || teamMembers[0];

      const assigneeOptions = teamMembers.map(m => 
        `<option value="${m.name}" ${m.name === task.assignee ? 'selected' : ''}>${m.name}</option>`
      ).join('');

      const statusOptions = [
        { value: 'todo', label: 'To Do' },
        { value: 'in-progress', label: 'In Progress' },
        { value: 'done', label: 'Done' }
      ].map(o => 
        `<option value="${o.value}" ${o.value === task.status ? 'selected' : ''}>${o.label}</option>`
      ).join('');

      const docLabel = task.doc ? `<div class="text-[10px] text-slate-500 font-medium bg-slate-100 rounded px-1.5 py-0.5 mt-1.5 inline-flex items-center gap-1 max-w-full truncate" title="${task.doc}">📄 ${task.doc}</div>` : '';

      return `
        <div id="${task.id}" draggable="true" ondragstart="dragStart(event)" ondragend="dragEnd(event)" class="bg-white border border-slate-200 rounded-lg p-3 hover:border-slate-300 transition-all cursor-grab active:cursor-grabbing space-y-2">
          <div class="flex items-start justify-between gap-2">
            <span class="text-xs font-normal text-slate-900 leading-normal break-words">${escapeHtml(task.title)}</span>
            <button onclick="deleteTask('${task.id}')" class="text-slate-400 hover:text-red-500 transition-colors" title="Delete task">
              <svg class="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
            </button>
          </div>

          ${docLabel}

          <div class="pt-2 border-t border-slate-100 flex items-center justify-between gap-2">
            <!-- Assignee and Initials Badge -->
            <div class="flex items-center gap-1.5 min-w-0">
              <div class="w-5 h-5 rounded-full flex items-center justify-center text-white text-[9px] font-bold shrink-0" style="background-color: ${member.color};" title="${member.name}">
                ${member.initials}
              </div>
              <select onchange="updateTaskAssignee('${task.id}', this.value)" class="bg-transparent text-[11px] text-slate-600 focus:outline-none cursor-pointer hover:text-slate-900 font-medium truncate max-w-[85px]">
                ${assigneeOptions}
              </select>
            </div>

            <!-- Interactive Column Transfer -->
            <select onchange="updateTaskStatus('${task.id}', this.value)" class="bg-transparent text-[11px] text-[#0b57d0] focus:outline-none cursor-pointer hover:text-[#0842a0] font-medium text-right">
              ${statusOptions}
            </select>
          </div>
        </div>
      `;
    }

    function renderBoard() {
      const searchTerm = (document.getElementById('searchInput')?.value || '').toLowerCase();
      const filterAssigneeVal = document.getElementById('filterAssignee')?.value || '';

      const columns = {
        'todo': document.getElementById('col-todo'),
        'in-progress': document.getElementById('col-in-progress'),
        'done': document.getElementById('col-done')
      };

      const counts = { 'todo': 0, 'in-progress': 0, 'done': 0 };

      // Clear columns
      Object.values(columns).forEach(col => { if(col) col.innerHTML = ''; });

      tasks.forEach(task => {
        const matchesSearch = task.title.toLowerCase().includes(searchTerm) || (task.doc && task.doc.toLowerCase().includes(searchTerm));
        const matchesAssignee = !filterAssigneeVal || task.assignee === filterAssigneeVal;

        if (matchesSearch && matchesAssignee) {
          if (columns[task.status]) {
            columns[task.status].insertAdjacentHTML('beforeend', renderCard(task));
            counts[task.status]++;
          }
        }
      });

      // Update Column Counters
      Object.keys(counts).forEach(status => {
        const el = document.getElementById(`count-${status}`);
        if (el) el.innerText = counts[status];
      });
    }

    // Set up Polling Loop and Initial State
    window.addEventListener('DOMContentLoaded', () => {
      renderBoard();
      if (envId) {
        loadSyncedState();
        setInterval(loadSyncedState, 2000);
      }
    });
  </script>
</body>
</html>
```
